rents supports.\\n\\n***","Descriptif du plan d''acc\00E8s":"","Jours et horaires d''ouverture":"Mercredi , Samedi","Labels":"","Date de cr\00E9ation - Etablissement":"10/10/2023","Date de fermeture":"","Fournisseur - Nom":"Mr Jean Fr\00E9d\00E9ric PIFFARELLY","Fournisseur - SIRET":"43274176700016","Fournisseur - adresse":"Mr Jean Fr\00E9d\00E9ric PIFFARELLY: 10 B Ruelle Jaune, 97414 Entre-Deux","Fournisseur - contacts":"pifjfred@hotmail.fr / 0692 37 72 47","Fournisseur - date de cr\00E9ation":"","Fournisseur - Code postal":"","Fournisseur - Bureau":"","Fournisseur - Code NAF":"","Fournisseur - Chambre consulaire":"","Fournisseur - Forme juridique":"","Fournisseur - CFE":"","Nb Produits":"","Coordonn\00E9es GPS":"-21.207616, 55.493859","Liste URL moteur":"","Tarif Montant":"","Tarif libell\00E9":"","Num taxe de s\00E9jour":"","Descriptif OTI":"","Accroche OTI":"","Status":"","commentaire":"","Date de derniere modification":"","Colones modifi\00E9es":"","Aire d''adh\00E9sion":"","source_system":"berta_v2_csv_export"}', 'pending', 'true'),
